@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h3>Notepad</h3>

<textarea @bind="_content" @bind:event="oninput" rows="12" class="notepad-textarea"></textarea>

<div class="notepad-toolbar">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    <span class="notepad-status">
        @if (_lastSavedAt is not null)
        {
            <text>Last saved at @_lastSavedAt.Value.ToString("HH:mm:ss")</text>
        }
    </span>
</div>

@code {
    private string _content = string.Empty;
    private string _savedContent = string.Empty;
    private DateTime? _lastSavedAt;
    private NotepadInterop? _interop;
    private Timer? _autoSaveTimer;

    private bool HasUnsavedChanges => _content != _savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);

            var stored = await _interop.LoadAsync();
            if (stored is not null)
            {
                _content = stored;
                _savedContent = stored;
                StateHasChanged();
            }

            _autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        await InvokeAsync(async () =>
        {
            if (HasUnsavedChanges)
            {
                await PerformSaveAsync();
                StateHasChanged();
            }
        });
    }

    private async Task SaveNowAsync()
    {
        await PerformSaveAsync();
    }

    private async Task PerformSaveAsync()
    {
        if (_interop is null) return;

        await _interop.SaveAsync(_content);
        _savedContent = _content;
        _lastSavedAt = DateTime.Now;
        await _interop.DisableBeforeUnloadAsync();
    }

    private async Task ClearAsync()
    {
        if (_interop is null) return;

        _content = string.Empty;
        _savedContent = string.Empty;
        _lastSavedAt = null;
        await _interop.ClearAsync();
        await _interop.DisableBeforeUnloadAsync();
    }

    private async Task OnContentChanged(ChangeEventArgs e)
    {
        _content = e.Value?.ToString() ?? string.Empty;

        if (_interop is not null)
        {
            if (HasUnsavedChanges)
                await _interop.EnableBeforeUnloadAsync();
            else
                await _interop.DisableBeforeUnloadAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_autoSaveTimer is not null)
            await _autoSaveTimer.DisposeAsync();

        if (_interop is not null)
            await _interop.DisposeAsync();
    }
}

